class Solution:
    def partition(self, s):
        out = []
        def is_pal(left, right):
            while left < right:
                if s[left] != s[right]:
                    return False
                left += 1
                right -= 1
            return True
        def dfs(index, path):
            if index == len(s):
                out.append(path[:])
                return
            for end in range(index, len(s)):
                if is_pal(index, end):
                    path.append(s[index:end + 1])
                    dfs(end + 1, path)
                    path.pop()
        dfs(0, [])
        return out
